import pytest

def test_create_encounter_end_before_start_rejected(api_client, clinician_auth_headers, existing_patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {
            "start": "2024-06-01T09:00:00Z",
            "end": "2024-06-01T08:00:00Z"
        }
    }
    resp = api_client.post("/Encounter", json=payload, headers=clinician_auth_headers)
    assert resp.status_code == 422
    body = resp.json()
    assert "issue" in body or "detail" in body

