def test_create_encounter_end_equals_start_boundary(api_client, clinician_auth_headers, existing_patient_id):
    ts = "2024-06-01T08:00:00Z"
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": ts, "end": ts}
    }
    resp = api_client.post("/Encounter", json=payload, headers=clinician_auth_headers)
    assert resp.status_code in (201, 422), (
        f"Expected 201 or 422 for zero-duration encounter, got {resp.status_code}"
    )
    body = resp.json()
    if resp.status_code == 201:
        assert "id" in body
        assert body["period"]["start"] == ts
        assert body["period"]["end"] == ts
    else:
        assert "issue" in body or "detail" in body

