def test_create_encounter_conflicting_state_transition_rejected(api_client, clinician_auth_headers, existing_patient_id, finished_encounter_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "partOf": {"reference": f"Encounter/{finished_encounter_id}"},
        "period": {
            "start": "2024-06-01T10:00:00Z",
            "end": "2024-06-01T11:00:00Z"
        }
    }
    resp = api_client.post("/Encounter", json=payload, headers=clinician_auth_headers)
    assert resp.status_code in (409, 422), (
        f"Expected 409 or 422 for conflicting state transition, got {resp.status_code}"
    )
    body = resp.json()
    assert "issue" in body or "detail" in body
